import{_ as e,o as t,c as a,a0 as r}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"⚖️ 自由市場與富豪排行榜","description":"","frontmatter":{},"headers":[],"relativePath":"Economy-Recycle.md","filePath":"Economy-Recycle.md"}'),c={name:"Economy-Recycle.md"};function n(l,o,s,i,d,h){return t(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="⚖️-自由市場與富豪排行榜" tabindex="-1">⚖️ 自由市場與富豪排行榜 <a class="header-anchor" href="#⚖️-自由市場與富豪排行榜" aria-label="Permalink to &quot;⚖️ 自由市場與富豪排行榜&quot;">​</a></h1><p>為了促進玩家之間的物資流通、保障自動化量產樂趣，本伺服器採用 <strong>100% 玩家主導的自由市場經濟系統</strong>。</p><hr><h2 id="🚫-1-系統收購功能關閉" tabindex="-1">🚫 1. 系統收購功能關閉 <a class="header-anchor" href="#🚫-1-系統收購功能關閉" aria-label="Permalink to &quot;🚫 1. 系統收購功能關閉&quot;">​</a></h2><p>本伺服器<strong>已全面關閉系統回收功能</strong>（即原本的 <code>/economy</code> 物資直接換金幣介面）：</p><ul><li>玩家無法將煤炭、鐵錠、鑽石、石頭或雜物等物資直接拋售給系統來換取金幣。</li><li>伺服器中沒有「系統無限印鈔」的金幣發放管道，所有金幣均靠交易與簽到流通。</li></ul><h3 id="💡-玩家獲取金幣的管道" tabindex="-1">💡 玩家獲取金幣的管道： <a class="header-anchor" href="#💡-玩家獲取金幣的管道" aria-label="Permalink to &quot;💡 玩家獲取金幣的管道：&quot;">​</a></h3><ol><li><strong>玩家間相互交易</strong>：透過建立 <a href="./Shop-Creation.html">箱子商店</a> 出售物資給其他玩家。</li><li><strong>每日簽到與幸運抽獎</strong>：每日透過遊戲內指令 <code>/checkin</code>、<code>/luckydraw</code> 或 Discord 連動機器人進行簽到抽獎，可穩定獲得金幣。</li><li><strong>商人生涯營收</strong>：經營商店，提領營業金。</li></ol><hr><h2 id="🏆-2-全服富豪排行榜-eco-top-或-economy-top" tabindex="-1">🏆 2. 全服富豪排行榜 (<code>/eco top</code> 或 <code>/economy top</code>) <a class="header-anchor" href="#🏆-2-全服富豪排行榜-eco-top-或-economy-top" aria-label="Permalink to &quot;🏆 2. 全服富豪排行榜 (`/eco top` 或 `/economy top`)&quot;">​</a></h2><p>玩家可以在遊戲內輸入 <strong><code>/eco top</code></strong>（或 <strong>/economy top</strong>）開啟伺服器富豪排行榜選單，查閱排行：</p><ul><li><strong>財富排行</strong>：系統會實時彙整全伺服器所有玩家的帳戶餘額（包含離線玩家），並在選單中依序顯示出金幣排名前 <strong>10 名</strong> 的富豪玩家。</li><li><strong>跨平台資料同步</strong>：該財富排名會即時同步至 Discord 機器人及網頁端儀表板，讓您在遊戲外也能隨時掌握伺服器的財富榜！</li></ul>',12)])])}const g=e(c,[["render",n]]);export{m as __pageData,g as default};
